-- calc_tables_head_count
-- Field: Tables.HeadCount
-- Type: aggregation | DataType: integer | Returns: INTEGER

CREATE OR REPLACE FUNCTION calc_tables_head_count(p_table_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COUNT(*) FROM guests WHERE assigned_table = (SELECT NULLIF(table_id, '') FROM tables WHERE table_id = p_table_id)))::integer;
$$ LANGUAGE sql STABLE;

-- calc_tables_open_seats
-- Field: Tables.OpenSeats
-- Type: calculated | DataType: integer | Returns: INTEGER

CREATE OR REPLACE FUNCTION calc_tables_open_seats(p_table_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((COALESCE(CASE WHEN ((SELECT seats FROM tables WHERE table_id = p_table_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((SELECT seats FROM tables WHERE table_id = p_table_id))::numeric ELSE NULL END, 0) - COALESCE(CASE WHEN (calc_tables_head_count(p_table_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_tables_head_count(p_table_id))::numeric ELSE NULL END, 0)))::integer;
$$ LANGUAGE sql STABLE;

-- calc_tables_over_capacity
-- Field: Tables.OverCapacity
-- Type: calculated | DataType: boolean | Returns: BOOLEAN

CREATE OR REPLACE FUNCTION calc_tables_over_capacity(p_table_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (calc_tables_head_count(p_table_id) > (SELECT seats FROM tables WHERE table_id = p_table_id))::boolean;
$$ LANGUAGE sql STABLE;

