-- calc_tables_happiness
-- Field: Tables.Happiness
-- Type: calculated | DataType: number | Returns: NUMERIC


CREATE OR REPLACE FUNCTION calc_tables_happiness(p_table_id TEXT)
RETURNS NUMERIC AS $$
  SELECT ((COALESCE(CASE WHEN (calc_tables_raw_happiness(p_table_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_tables_raw_happiness(p_table_id))::numeric ELSE NULL END, 0) - COALESCE(CASE WHEN ((COALESCE(CASE WHEN (CASE WHEN calc_tables_over_capacity(p_table_id) THEN (25)::text ELSE (0)::text END)::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (CASE WHEN calc_tables_over_capacity(p_table_id) THEN (25)::text ELSE (0)::text END)::numeric ELSE NULL END, 0) + COALESCE(CASE WHEN (calc_tables_side_skew(p_table_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_tables_side_skew(p_table_id))::numeric ELSE NULL END, 0)))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((COALESCE(CASE WHEN (CASE WHEN calc_tables_over_capacity(p_table_id) THEN (25)::text ELSE (0)::text END)::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (CASE WHEN calc_tables_over_capacity(p_table_id) THEN (25)::text ELSE (0)::text END)::numeric ELSE NULL END, 0) + COALESCE(CASE WHEN (calc_tables_side_skew(p_table_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_tables_side_skew(p_table_id))::numeric ELSE NULL END, 0)))::numeric ELSE NULL END, 0)))::numeric;
$$ LANGUAGE sql STABLE;

-- calc_tables_grade
-- Field: Tables.Grade
-- Type: calculated | DataType: string | Returns: TEXT

CREATE OR REPLACE FUNCTION calc_tables_grade(p_table_id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN (calc_tables_violation_count(p_table_id))::NUMERIC > 0 THEN ('Conflict')::text ELSE (CASE WHEN calc_tables_over_capacity(p_table_id) THEN ('Over Capacity')::text ELSE (CASE WHEN (calc_tables_happiness(p_table_id))::NUMERIC >= 15 THEN ('Great')::text ELSE (CASE WHEN (calc_tables_happiness(p_table_id))::NUMERIC >= 5 THEN ('OK')::text ELSE ('Cold')::text END)::text END)::text END)::text END)::text;
$$ LANGUAGE sql STABLE;

