-- calc_tables_side_skew
-- Field: Tables.SideSkew
-- Type: calculated | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_tables_side_skew(p_table_id TEXT)
RETURNS INTEGER AS $$
  SELECT (CASE WHEN calc_tables_bride_side_count(p_table_id) > calc_tables_groom_side_count(p_table_id) THEN ((COALESCE(CASE WHEN (calc_tables_bride_side_count(p_table_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_tables_bride_side_count(p_table_id))::numeric ELSE NULL END, 0) - COALESCE(CASE WHEN (calc_tables_groom_side_count(p_table_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_tables_groom_side_count(p_table_id))::numeric ELSE NULL END, 0)))::text ELSE ((COALESCE(CASE WHEN (calc_tables_groom_side_count(p_table_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_tables_groom_side_count(p_table_id))::numeric ELSE NULL END, 0) - COALESCE(CASE WHEN (calc_tables_bride_side_count(p_table_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_tables_bride_side_count(p_table_id))::numeric ELSE NULL END, 0)))::text END)::integer;
$$ LANGUAGE sql STABLE;

