-- calc_relationships_same_table
-- Field: Relationships.SameTable
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_relationships_same_table(p_rel_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((calc_relationships_guest_a_table(p_rel_id) IS NOT NULL AND calc_relationships_guest_a_table(p_rel_id) = calc_relationships_guest_b_table(p_rel_id)))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_relationships_seated_table
-- Field: Relationships.SeatedTable
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_relationships_seated_table(p_rel_id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN calc_relationships_same_table(p_rel_id) THEN (calc_relationships_guest_a_table(p_rel_id))::text ELSE ('')::text END)::text;
$$ LANGUAGE sql STABLE;

-- calc_relationships_effective_score
-- Field: Relationships.EffectiveScore
-- Type: calculated | DataType: number | Returns: NUMERIC


CREATE OR REPLACE FUNCTION calc_relationships_effective_score(p_rel_id TEXT)
RETURNS NUMERIC AS $$
  SELECT (CASE WHEN calc_relationships_same_table(p_rel_id) THEN (CASE WHEN (SELECT NULLIF(kind, '') FROM relationships WHERE rel_id = p_rel_id) = 'must-not' THEN (-50)::text ELSE ((SELECT weight FROM relationships WHERE rel_id = p_rel_id))::text END)::text ELSE (0)::text END)::numeric;
$$ LANGUAGE sql STABLE;

-- calc_relationships_is_must_not_violation
-- Field: Relationships.IsMustNotViolation
-- Type: calculated | DataType: boolean | Returns: BOOLEAN

CREATE OR REPLACE FUNCTION calc_relationships_is_must_not_violation(p_rel_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (((SELECT NULLIF(kind, '') FROM relationships WHERE rel_id = p_rel_id) = 'must-not' AND calc_relationships_same_table(p_rel_id)))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_relationships_is_satisfied
-- Field: Relationships.IsSatisfied
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_relationships_is_satisfied(p_rel_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (((((SELECT weight FROM relationships WHERE rel_id = p_rel_id))::NUMERIC > 0 AND calc_relationships_same_table(p_rel_id)) OR (((SELECT weight FROM relationships WHERE rel_id = p_rel_id))::NUMERIC < 0 AND NOT (calc_relationships_same_table(p_rel_id)))));
$$ LANGUAGE sql STABLE;

-- calc_relationships_violation_table
